// frontend/src/components/Dashboard/Dashboard.js
import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Grid,
  Paper,
  Typography,
  Button,
  AppBar,
  Toolbar,
  IconButton,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Alert,
  CircularProgress,
  Card,
  CardContent,
  Chip,
  useTheme,
  useMediaQuery
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  TrendingUp,
  TrendingDown,
  AccountBalanceWallet,
  ShowChart,
  History,
  Sync
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import authService from '../../services/authService';
import dashboardService from '../../services/dashboardService';
import StatsCards from './StatsCards';
import ProfitChart from './ProfitChart';
import TradesTable from './TradesTable';
import AccountBalance from './AccountBalance';

const Dashboard = () => {
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  const [user, setUser] = useState(null);
  const [anchorEl, setAnchorEl] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState('');
  const [dashboardData, setDashboardData] = useState({
    stats: null,
    openTrades: [],
    closedTrades: [],
    profitData: [],
    balance: null
  });

  useEffect(() => {
    loadDashboardData();
  }, []);

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      setError('');

      // Verificar sessão do usuário
      const sessionData = await authService.checkSession();
      setUser(sessionData.user);

      // Carregar dados do dashboard em paralelo
      const [stats, openTrades, closedTrades, profitData, balance] = await Promise.all([
        dashboardService.getUserStats(),
        dashboardService.getOpenTrades(),
        dashboardService.getClosedTrades(),
        dashboardService.getProfitCurveData(),
        dashboardService.getAccountBalance()
      ]);

      setDashboardData({
        stats,
        openTrades: Array.isArray(openTrades) ? openTrades : [],
        closedTrades: Array.isArray(closedTrades) ? closedTrades : [],
        profitData: Array.isArray(profitData) ? profitData : [],
        balance
      });
    } catch (error) {
      console.error('Erro ao carregar dashboard:', error);
      setError('Erro ao carregar dados do dashboard');

      if (error.message === 'Não autenticado') {
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadDashboardData();
    setRefreshing(false);
    toast.success('Dados atualizados!');
  };

  const handleSyncTrades = async () => {
    try {
      setRefreshing(true);
      await dashboardService.syncTrades();
      await loadDashboardData();
      toast.success('Trades sincronizados com sucesso!');
    } catch (error) {
      console.error('Erro ao sincronizar trades:', error);
      toast.error('Erro ao sincronizar trades');
    } finally {
      setRefreshing(false);
    }
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = async () => {
    try {
      await authService.logout();
      navigate('/login');
      toast.success('Logout realizado com sucesso!');
    } catch (error) {
      console.error('Erro no logout:', error);
      toast.error('Erro ao fazer logout');
    }
    handleMenuClose();
  };

  if (loading) {
    return (
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh',
          flexDirection: 'column',
          gap: 2
        }}
      >
        <CircularProgress size={60} />
        <Typography variant="h6" color="text.secondary">
          Carregando dashboard...
        </Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* AppBar */}
      <AppBar position="static" elevation={0} sx={{ bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
        <Toolbar>
          <Typography
            variant="h6"
            component="div"
            sx={{
              flexGrow: 1,
              fontWeight: 'bold',
              color: 'primary.main'
            }}
          >
            Bit Nova
          </Typography>

          {/* Botões de ação */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mr: 2 }}>
            <Button
              startIcon={<Sync />}
              onClick={handleSyncTrades}
              disabled={refreshing}
              size="small"
              variant="outlined"
              sx={{ display: { xs: 'none', sm: 'flex' } }}
            >
              Sincronizar
            </Button>

            <IconButton
              onClick={handleRefresh}
              disabled={refreshing}
              color="primary"
            >
              <Refresh />
            </IconButton>
          </Box>

          {/* Menu do usuário */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            {!isMobile && user && (
              <Typography variant="body2" color="text.primary">
                Olá, {user.full_name.split(' ')[0]}
              </Typography>
            )}
            <IconButton
              size="large"
              onClick={handleMenuOpen}
              color="inherit"
            >
              <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.main' }}>
                {user?.full_name?.charAt(0) || <AccountCircle />}
              </Avatar>
            </IconButton>
          </Box>

          <Menu
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={handleMenuClose}
            transformOrigin={{ horizontal: 'right', vertical: 'top' }}
            anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
          >
            <MenuItem disabled>
              <Typography variant="body2" color="text.secondary">
                {user?.email}
              </Typography>
            </MenuItem>
            <Divider />
            <MenuItem onClick={handleLogout}>
              <Logout fontSize="small" sx={{ mr: 1 }} />
              Sair
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Conteúdo principal */}
      <Container maxWidth="xl" sx={{ py: 3 }}>
        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
          </Alert>
        )}

        <Grid container spacing={3}>
          {/* Cards de estatísticas */}
          <Grid item xs={12}>
            <StatsCards stats={dashboardData.stats} loading={refreshing} />
          </Grid>

          {/* Saldo da conta */}
          <Grid item xs={12} md={4}>
            <AccountBalance balance={dashboardData.balance} loading={refreshing} />
          </Grid>

          {/* Gráfico de lucro */}
          <Grid item xs={12} md={8}>
            <ProfitChart data={dashboardData.profitData} loading={refreshing} />
          </Grid>

          {/* Trades abertos */}
          <Grid item xs={12}>
            <Paper sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <ShowChart color="primary" />
                  Posições Abertas
                </Typography>
                <Chip
                  label={`${dashboardData.openTrades.length} posições`}
                  color="primary"
                  size="small"
                />
              </Box>
              <TradesTable trades={dashboardData.openTrades} type="open" loading={refreshing} />
            </Paper>
          </Grid>

          {/* Histórico de trades */}
          <Grid item xs={12}>
            <Paper sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <History color="primary" />
                  Histórico de Trades
                </Typography>
                <Chip
                  label={`${dashboardData.closedTrades.length} trades`}
                  color="secondary"
                  size="small"
                />
              </Box>
              <TradesTable trades={dashboardData.closedTrades} type="closed" loading={refreshing} />
            </Paper>
          </Grid>
        </Grid>
      </Container>
    </Box>
  );
};

export default Dashboard;
